// SPI Master Controller
module top_module(
	input clk,
	input load,
	input shift,
	input [15:0] data,
	output reg [15:0] q);always @(posedge clk) begin
		if (load)
			q <= data;
		else if (shift)
			q <= {1'b0, q[15:1]};
	end
endmodule

params_used.parameters:
// This is a 16-bit shift register with synchronous load and shift left enable.
// (1) load: Loads shift register with data[15:0] instead of shifting. Synchronous active high.
// (2) shift: If high, shifts left by one bit.
// (3) q: The contents of the shift register.
